var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"죄송합니다, 인도자님. 물자를 공급하는 것이 쉽지 않아 마차 수리에는 시간이 걸릴 듯싶군요.","JPN":"申し訳ありません、導き手様。物資の供給が少ないので、馬車の修理に時間がかかりそうです。","ENG":"My apologies, Star Guide. With supply lines strained, the carriage repairs may take some time.","TWN":"抱歉，引導者大人。供應物資並不容易，修理馬車可能需要一些時間。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"수리 후 안전검사까지 마쳐야 하니 못해도 2주일은 필요합니다만…….","JPN":"修理後の安全点検までしないといけないですから、少なくとも2週間は必要ですが……","ENG":"After repairs, we'll also need to conduct a safety check. It'll take at least two weeks...","TWN":"修理後還需要進行安全檢查，至少需要兩周時間……"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"급히 출발해야 한다면 최대한 빠른 시일 내에 수리를 끝마치겠습니다.","JPN":"急いで出発する必要があるなら、なるべく早く修理を終わらせます。","ENG":"But if you need to leave urgently, I'll try to finish the work as quickly as possible.","TWN":"如果需要緊急出發，我會儘快完成修理。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"아뇨. 그러실 필요 없습니다.","JPN":"いいえ。その必要はありません。","ENG":"No, that won't be necessary.","TWN":"不，不必這樣。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"전 괜찮으니 무리하지 말고 천천히 일하세요, 클링턴 씨.","JPN":"私は大丈夫ですのでごゆっくりどうぞ、クリントンさん。","ENG":"I'm fine, so don't push yourself. Take your time, Mr. Clinton.","TWN":"我沒關係，克林頓先生，請不要勉強，慢慢來吧。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"……또 이곳에 계시는군요.","JPN":"……またここにいらしゃったのですか。","ENG":"...You're here again.","TWN":"……你又在這裡啊。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"이곳에서 키우는 양들은 사납다고 전에 말씀드렸습니다만.","JPN":"ここで飼っている羊たちは、気が荒いとお伝えしたはずですが。","ENG":"If I recall, I warned you these sheep can be aggressive.","TWN":"我記得之前說過這裡養的羊很兇猛。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"사나운 양이래 봐야 괴수만은 못하지요.","JPN":"いくら気が荒くても怪獣よりは大人しいでしょう。","ENG":"Aggressive sheep are still nothing compared to monsters.","TWN":"再兇猛的羊也比不上怪獸。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"시야가 트여 마을을 둘러보기 또한 안성맞춤이니, 이만한 장소를 찾기 어렵겠습니다.","JPN":"視界が開けていますので、村を見渡すのにここ以上の場所はありません。","ENG":"The open view makes it a perfect place to look over the village. It's hard to find a better spot.","TWN":"視野開闊，環顧村莊也是絕佳之選，這樣的地方很難找到。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"전 신경 쓰지 마시고, 부디.","JPN":"私のことはお構いなく。","ENG":"Please, pay me no mind.","TWN":"請不要在意，務必如此。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"……예, 알겠습니다.","JPN":"……はい、かしこまりました。","ENG":"...Understood.","TWN":"……是，明白。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"narration","speaker":null,"text":{"KOREA":"귀족에게 잘 보이려는 사람들과는 달리 그는 내게 별다른 말은 하지 않았다.","JPN":"貴族に良い印象を与えようとする人々とは違い、彼は私にあまり話しかけることはなかった。","ENG":"Unlike those who tried to curry favor with nobles, he never said much to me.","TWN":"與那些想討好貴族的人不同，他對我沒有多說什麼。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"narration","speaker":null,"text":{"KOREA":"거리를 유지한 채, 이따금씩 내 상태를 확인하려 할 뿐.","JPN":"距離を取ったまま、たまに私の様子を確認するだけ。","ENG":"He kept his distance, only occasionally checking in.","TWN":"保持距離，只是偶爾想確認我的狀態而已。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"양과 사투하는 그를 바라보는 건 썩 나쁘지 않은 광경이었다.","JPN":"羊と格闘している彼を見るのは、なかなか悪くない光景だった。","ENG":"Watching him wrestle with the sheep wasn't a bad sight.","TWN":"看著他與羊搏鬥的場景，倒也不算太糟糕。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"다른 목동들은 목양견을 함께 사육하던데, 이곳에는 그런 동물이 보이지 않는군요.","JPN":"他の羊飼いは牧羊犬を一緒に飼っているのに、ここにはそのような動物は見当たりませんね。","ENG":"Other shepherds usually keep sheepdogs. I don't see any here.","TWN":"其他牧童都和牧羊犬一起飼養，但這裡似乎沒有看到這樣的動物。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L24_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"최소한의 검술은 익혔으니, 짐승들로부터 가축을 지키는 것은 어려운 일이 아닙니다.","JPN":"最低限の剣術は身につけているので、獣から家畜を守ることは難しくありません。","ENG":"I've learned the basics of swordsmanship. Protecting livestock from beasts isn't that difficult.","TWN":"至少掌握了基本的劍術，保護牲畜免受野獸侵害並不困難。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"검술에 능한 제 친척 역시 마을을 지키기 위해 힘을 보태고 있고요.","JPN":"剣術の腕がある私の親戚もまた、村を守るために頑張っています。","ENG":"One of my relatives, who's more skilled with the sword, helps protect the village as well.","TWN":"我擅長劍術的親戚也在為守護村莊貢獻力量。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"narration","speaker":null,"text":{"KOREA":"그렇게, 하루가 지나고.","JPN":"そうして、一日が過ぎ。","ENG":"And so, another day passed.","TWN":"就這樣，一天過去了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"분명 위험하다 말하지 않았습니까.","JPN":"確かに危険だと言ったはずです。","ENG":"I told you it was dangerous.","TWN":"你不是說過很危險嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L31_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"제가 한눈을 팔았더라면, 영애 분의 귀한 몸에 상처가 났을 겁니다.","JPN":"私がよそ見をしていたら、ご令嬢はお怪我をされていたことでしょう。","ENG":"If I'd let my guard down, you might've gotten hurt.","TWN":"如果我一時疏忽，小姐你尊貴的身體就會受傷。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제 한 몸 지킬 여력은 충분하니 걱정하실 필요 없습니다.","JPN":"自分の身を守る力は十分ありますので、心配しないでください。","ENG":"I'm more than capable of protecting myself. You don't have to worry.","TWN":"我有足夠的能力保護自己，不用擔心。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그래도 혹여 걱정되신다면… 그래요.","JPN":"それでも心配だと言うなら……そうですね。","ENG":"But if you're that concerned... All right.","TWN":"不過如果你還是擔心的話……也是可以的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"당신의 검을, 제가 잠시 손볼 수 있을까요?","JPN":"よろしければ、貴方の剣を少々見せてもらってもいいですか？","ENG":"May I take a look at your sword?","TWN":"你的劍，我可以稍微處理一下嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"제 검을 말입니까?","JPN":"私の剣を、ですか？","ENG":"My sword?","TWN":"我的劍嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"영리한 짐승은 발톱을 내민 포식자 앞에서 제 몸을 사리는 법이지요.","JPN":"賢い獣は爪をむきだした捕食者の前では慎重になるものです。","ENG":"Smart animals know to keep their distance when they sense a predator's claws.","TWN":"聰明的野獸在露出爪子的掠食者面前懂得保護自己。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"무뎌진 칼날을 벼려내 날을 내세운다면, 위기감을 느낀 양떼들이 잠잠해질 겁니다.","JPN":"鈍った剣を鍛えて刃を鋭くすれば、危険を感じた羊たちが大人しくなることでしょう。","ENG":"If we sharpen that dull blade, the sheep might feel the threat and calm down.","TWN":"如果磨利鈍化的刀刃，感到危機的羊群就會安靜下來。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"영애께서 대장공의 기량을 지니셨다는 겁니까?","JPN":"ご令嬢は鍛冶仕事に自信をお持ちなのですか？","ENG":"Are you saying you're skilled in smithing, milady?","TWN":"意思是小姐擁有匠人的手藝嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제입으로 말하기 뭐하지만 무구를 다루는 데는 제법 조예가 깊은 편입니다.","JPN":"自分で言うのも恥ずかしいのですが、武具の扱いにおいてはかなり造詣の深い方でして。","ENG":"I may not sound modest saying this, but I know a thing or two about working with weapons.","TWN":"雖然不好意思自誇，但我在使用武具方面頗有造詣。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예. 제국에서도 가히 최고라 일컬어지죠.","JPN":"ええ。帝国でも最高と言われております。","ENG":"Yes, even within the Empire, I'm considered one of the best.","TWN":"是的。在帝國中也被稱為最頂尖的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L45_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"뭐하다고 한 것 치고는 제법 말씀하시는군요.","JPN":"恥ずかしいというわりには平然と自慢をしているようですが。","ENG":"You sure don't sound modest for someone who claimed to be humble.","TWN":"看你說得那麼輕鬆，沒想到手藝不錯。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"narration","speaker":null,"text":{"KOREA":"이틀, 사흘이 지나고.","JPN":"二日、三日が過ぎ。","ENG":"Two days passed, then three.","TWN":"兩天，三天過去了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"졌습니다. 설마 영애께서 검술의 귀재이신 줄은 몰랐군요.","JPN":"私の負けです。まさかご令嬢が剣術の鬼才であられたとは。","ENG":"I yield. I never imagined you'd be a master of swordsmanship.","TWN":"輸了。沒想到小姐竟然是劍術高手啊。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"아뇨. 아홉 대륙에서 이름을 날린 기사들에 비하면 범재에 불과합니다.","JPN":"いいえ。9つの大陸で名をはせた騎士たちに比べましたら、凡才です。","ENG":"No, compared to knights renowned across the nine continents, I'm nothing special.","TWN":"不。我不過是個平庸之輩，怎能與在九大陸上聲名遠揚的騎士們相比呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"오히려 검술의 재능만으로는 당신이 저를 앞서는 듯하지만…….","JPN":"むしろ剣術の才能では貴方が私よりも上に見えますが……","ENG":"In fact, you might surpass me when it comes to natural talent...","TWN":"反而在劍術的天賦上，似乎是你勝過了我……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"당장은 다른 사람을 흉내내는 듯한 움직임이 발목을 잡는 듯하군요.","JPN":"今は他人の真似をしているかのような動きが足を引っ張っています。","ENG":"But for now, your movements feel like you're imitating someone else, and that's holding you back.","TWN":"目前看來，模仿他人的動作似乎會成為你的絆腳石。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"……어렸을 적, 무턱대고 검을 잡은 이후 한 번을 이기지 못한 사내가 있습니다.","JPN":"……小さい頃、何も考えず剣を手に取ってから、一度も勝てなかった男がいます。","ENG":"...There was someone I could never beat after recklessly picking up a sword as a child.","TWN":"……小時候，有個男人在毫無準備的情況下拿起劍，卻從未贏過一次。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"어쩌면 본능적으로 그의 움직임을 따라하고 있을지도 모르겠군요.","JPN":"もしかしたら本能的に彼の動きを真似ていたのかもしれませんね。","ENG":"Maybe I've subconsciously been mimicking him ever since.","TWN":"也許我正在本能地模仿他的動作。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"한 번을 이기지 못했다라… 과연, 그건 분하겠네요.","JPN":"一度も勝てなかった……なるほど、それは悔しかったでしょう。","ENG":"Never won even once...? That must've been frustrating.","TWN":"一次都沒贏過嗎……果然，那會讓人感到不甘心呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"이렇게 된 이상 제가 직접 검술을 지도해드리겠습니다.","JPN":"せっかくですから、私が直接剣術を指導して差し上げます。","ENG":"In that case, allow me to train you myself.","TWN":"既然如此，我將親自指導你的劍術。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제국에서 손꼽히는 백작령의 검술을 익힌다면 대부분의 기사는 맥을 못 출 거예요.","JPN":"帝国でも指折りの、伯爵領の剣術を身につければ、大抵の騎士は敵わないでしょう。","ENG":"Once you learn the County's swordsmanship, few knights will be able to stand against you.","TWN":"如果掌握了帝國數一數二的伯爵領地劍術，大部分騎士都會對你無可奈何。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"죄송하지만, 그래도 이기기는 힘들 것 같군요.","JPN":"申し訳ありませんが、それでも勝てないと思います。","ENG":"Apologies, but I still don't think I could win.","TWN":"抱歉，恐怕還是很難贏。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제법 자존심을 긁을 줄 아시는군요, 당신.","JPN":"プライドを掻き立てるのがうまいですね、貴方。","ENG":"You certainly know how to bruise someone's pride.","TWN":"你還真會戳人自尊心呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L19_1","type":"narration","speaker":null,"text":{"KOREA":"어느덧 열흘이 넘는 시간이 지났을 무렵.","JPN":"いつの間にか、十日を超える日が流れて。","ENG":"Before I knew it, more than ten days had gone by.","TWN":"不知不覺間，已經過去了十多天。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"나는 자신도 놀랄 만큼 그에게 벽을 허물었음을 느꼈다.","JPN":"私は、自分でもおかしく思うくらい、彼に馴染んでいた。","ENG":"And to my own surprise, I found myself opening up to him.","TWN":"我感到自己竟然對他敞開了心扉，連自己都感到驚訝。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L23_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふうん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"며칠 사이에 움직임이 많이 좋아지셨습니다. 가르치는 보람이 있네요.","JPN":"数日で動きがだいぶ良くなりました。教え甲斐がありますね。","ENG":"Your form has improved quite a bit over the last few days. It's rewarding to teach someone like you.","TWN":"這幾天你的動作進步很大。教導你真是值得的呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"감사합니다. 확실히 도움을 청한 이후 제 스스로의 움직임에 이따금씩 놀라는군요.","JPN":"ありがとうございます。確かにお願いしてからの自分の動きに時々驚かされています。","ENG":"Thank you. Since I asked for your help, even I'm surprised by my own movements at times.","TWN":"謝謝你。自從尋求幫助後，我時常對自己的行動感到驚訝。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"지금이라면 친척과의 대련에서 옷깃 정도는 베어볼 수 있을 것 같습니다.","JPN":"今なら親戚との立ち合い稽古で、襟くらいは斬れると思います。","ENG":"I think I could at least graze my cousin's sleeve in a spar now.","TWN":"現在的話，和親戚對練時應該能削到衣角了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"……백작령의 검술이 옷깃을 베는데 그치는 것도 자존심이 상하는데 말이죠.","JPN":"……伯爵領の剣術で襟を斬るだけというのもプライドが傷つきますが。","ENG":"...Even saying that much makes me feel like my House's swordsmanship is being slighted.","TWN":"……伯爵領地的劍術僅僅能割破衣領，這也太傷自尊了吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"이런, 벌써 시간이 이렇게 되었군요. 오늘은 이만 가보겠습니다.","JPN":"あら、もうこんな時間ですね。今日はこれで失礼します。","ENG":"Oh my, look at the time. I'll head back for the day.","TWN":"哎呀，已經這麼晚了。今天就到這裡吧，我先走了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"이르군요. 평소라면 해가 떨어지기 직전까지 계셨을 텐데요.","JPN":"今日は早いのですね。普段なら日が暮れる直前までお帰りにならないのに。","ENG":"That's early. You usually stay until just before sunset.","TWN":"來得真早啊。平時你都會待到太陽快落山的時候呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"이곳을 떠날 날이 머지않았으니 관련된 채비를 갖추어야지요.","JPN":"もうすぐここを離れることになりますので、その支度をしなければいけませんから。","ENG":"We'll be leaving soon, so I need to prepare.","TWN":"離開這裡的日子不遠了，我得做好相關的準備。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"저와 함께 있고 싶다면, 제가 있는 숙소에 머무르게 해드릴 수는 있습니다만?","JPN":"私と一緒にいたいとおっしゃるのなら、私の宿に泊らせてさしあげましょうか？","ENG":"If you'd like to stay with me, I can arrange a room at my lodging.","TWN":"如果你想和我在一起，我可以讓你住在我的宿舍裡。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"영애분께 손을 댔다간 빈말로라도 제 목이 남아나진 않겠군요.","JPN":"ご令嬢に手を出したら、自分の命が危うくなりそうです。","ENG":"If I laid a hand on you, I'd lose my head. Literally.","TWN":"如果對小姐動手，即使是開玩笑，我的腦袋也保不住了吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"후후. 기왕 손을 댄다면 로맨틱한 분위기에서 부탁드립니다.","JPN":"ふふ。手を出すおつもりでしたら、ロマンチックな雰囲気でお願いします。","ENG":"Haha. If you ever do, make sure it's in a romantic setting.","TWN":"呵呵。既然要動手的話，請在浪漫的氛圍中進行吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그래요. 상냥하게 이름을 불러주면 더 좋을 것 같네요.","JPN":"そうですね。優しく名前を呼ぶとか。","ENG":"And please, call my name gently while you're at it.","TWN":"是啊，如果能溫柔地叫名字就更好了呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L40_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"……고려해보겠습니다.","JPN":"……考えてみます。","ENG":"...I'll consider it.","TWN":"……我會考慮的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L41_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예. 긍정적인 검토 부탁드릴게요.","JPN":"ええ。前向きに検討してください。","ENG":"Please do. I look forward to your thoughtful consideration.","TWN":"好的，請積極考慮。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"또 봐요, 알렌.","JPN":"ごきげんよう、アレン。","ENG":"See you again, Allen.","TWN":"再見，艾倫。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"어렵군. 거리감이 가까운 여성을 상대하는 건.","JPN":"難しいな。距離感の近い女性を相手するのは。","ENG":"She's tough to deal with. I've never been good with women who close the distance like that.","TWN":"真是難辦。應對距離感較近的女性可不容易。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그녀석처럼 둔감하게 태어났다면 별다른 오해가 생길 일도 없을 텐데 말이야.","JPN":"あいつのように鈍感だったら、誤解が発生することもないだろうが。","ENG":"If I were as insensitive as him, there'd be no particular misunderstanding...","TWN":"如果像那傢伙一樣天生遲鈍，就不會有什麼誤會了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"음? 무언가 두고 온 물건이라도…….","JPN":"うん？　何か忘れ物でも……","ENG":"Mm? Did you forget something...?","TWN":"嗯？是有什麼東西落下了嗎……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"아니, 너였나. 여긴 위험하니 출입 금지라고 말했을 텐데.","JPN":"君だったか。ここは危険だから立ち入り禁止だと言っておいたはずだが。","ENG":"Oh, it's you. I told you this area was dangerous. No trespassing.","TWN":"原來是你。我應該說過這裡很危險，禁止出入吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MAN_PRIDE_NULL_NULL","text":{"KOREA":"미, 미안. 정신이 팔린 탓에 생각 없이 계속 걷기만 했네.","JPN":"ご、ごめん。ぼーっとしてて、考えもなくひたすら歩いちゃったんだ。","ENG":"S-sorry. I was lost in thought and just kept walking.","TWN":"對，對不起。因為精神恍惚，就走到這裡了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MAN_PRIDE_NULL_NULL","text":{"KOREA":"금방 돌아갈게. 미안해.","JPN":"すぐ戻るね。ごめん。","ENG":"I'll head back now. I'm sorry.","TWN":"我馬上離開，對不起。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"……눈시울이 붉군. 무슨 일이지?","JPN":"……目が赤いな。どうした？","ENG":"...Your eyes are red. Did something happen?","TWN":"……眼眶紅了。發生什麼事了？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MAN_PRIDE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MAN_PRIDE_NULL_NULL","text":{"KOREA":"아, 알렌…….","JPN":"あ、アレン……","ENG":"A-Allen...","TWN":"艾，艾倫……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MAN_PRIDE_NULL_NULL","text":{"KOREA":"나… 어쩌면 좋아?","JPN":"僕……どうしたらいいのかな？","ENG":"What... am I supposed to do?","TWN":"我……該怎麼辦呢？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"센트럴 팰리스에 복귀하라는 칙명이 내려왔다고요?","JPN":"セントラルパレスに復帰するようにとの王命が？","ENG":"A royal order to return to the Central Palace?","TWN":"聽說有王命讓我們回到聖特羅貝里斯嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"예. 남서부 카시라스 방어선이 돌파되어 마왕군의 위험성이 부각된 만큼.","JPN":"はい。南西部のカシラス防御線が突破され、魔王軍の危険性が高くなった今。","ENG":"Yes. The southwestern Kashiras defense line has been breached, and the Demon Lord's army poses a growing threat.","TWN":"是的。由於西南部凱西拉斯防線被突破，魔王軍的危險性已經顯現出來。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"황실에서도 호위 병력의 규모를 조정해야 한다고 여긴 것 같습니다.","JPN":"王家も護衛兵力の規模を調整すべきと思っているようです。","ENG":"The royal family seems to think they need to restructure the escort forces.","TWN":"看來王室也認為需要調整護衛兵力的規模。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"하지만 너무 갑작스럽군요. 그러한 칙명이 있었다면 전령과 함께 최소한의 병력이 붙었을 겁니다.","JPN":"ですが、突然すぎます。そのような勅命があったのなら、伝令とともに最低限の兵力が来たはずです。","ENG":"This is very sudden. If it were truly an official order, a herald and at least a few guards would've been sent.","TWN":"但是太突然了。如果有這樣的命令，至少會有使者和少量的兵力隨行。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"인도자님도 아시겠지만 병력을 부지하는 것조차 버거운 상황입니다.","JPN":"導き手もご存じでしょうが、兵力を維持することさえも難しい状況です。","ENG":"As you know, we're barely able to maintain our forces.","TWN":"引導者大人，你也知道，現在連維持兵力都很困難。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"납득하기 힘든 상황이라는 것은 이해하나… 당장은 칙명을 따르는 것이 어떠십니까?","JPN":"納得しかねるお気持ちは十分理解しておりますが……とりあえずは王命に従われてはいかがでしょうか？","ENG":"I understand the situation is hard to accept... but perhaps we should comply for now.","TWN":"雖然理解這是一個難以接受的情況……但現在還是遵從王命吧？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MAID_PRIDE_NULL_A","text":{"KOREA":"맞아요, 인도자님. 이런 외지에 있는 것보다 제도에 있는 편이 안전할 거예요.","JPN":"そうですよ、導き手。こんな辺鄙なところにいるよりは、帝都にいた方がずっと安全です。","ENG":"That's right, Star Guide. You'll be safer in the capital than out here in the provinces.","TWN":"沒錯，引導者大人。比起在這種偏僻的地方，還是在制度裡更安全。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAID_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAID_PRIDE_NULL_B","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"MAID_PRIDE_NULL_B","text":{"KOREA":"전하께서 생각을 바꾸시기 전에 돌아가시는 것이 어떻겠나요?","JPN":"殿下の気が変わる前に、お戻りになったらどうですか？","ENG":"It might be best to return before His Majesty changes his mind.","TWN":"在殿下改變主意之前，你是否應該回去呢？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAID_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAID_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"알겠습니다. 오늘은 날이 늦었으니 내일 날이 밝는 대로 출발하죠.","JPN":"わかりました。今日はもう遅いので、明日夜が明けたら出発しましょう。","ENG":"Understood. It's already late, so we'll depart first thing tomorrow.","TWN":"知道了。今天天色已晚，明天一早出發吧。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"클링턴 씨께는 제가 말씀드리겠습니다.","JPN":"クリントンさんには私から話しておきます。","ENG":"I'll inform Mr. Clinton myself.","TWN":"我會告訴克林頓先生的。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"음?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAID_PRIDE_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"리나 양. 그건 못 보던 금반지네요.","JPN":"リナさん。初めて見る金の指輪ですね。","ENG":"Rina. That's a new gold ring, isn't it?","TWN":"莉娜，那是我沒見過的金戒指呢。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAID_PRIDE_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"군자금이 그리 넉넉치 않은 것으로 기억하는데, 경비에서 지출한 것은 아니겠죠?","JPN":"軍資金に余裕がなかったように思うのですが、経費からの支出ではありませんよね？","ENG":"As I recall, our funds weren't particularly generous. That didn't come from our budget, did it?","TWN":"我記得軍費並不充裕，你不會是從經費裡支出的吧？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MAID_PRIDE_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"MAID_PRIDE_NULL_A","text":{"KOREA":"설마요, 인도자님. 이건 고생이 많다며 마을 주민분이 선물해주신 거예요.","JPN":"まさか、導き手。これは苦労を労って村の住民が差し入れてくれたものです。","ENG":"Of course not, Star Guide. A villager gave it to me as a thank-you gift.","TWN":"怎麼可能，引導者大人。這是村民們為了感謝你的辛苦而送給你的禮物。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MAID_PRIDE_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"MAID_PRIDE_NULL_A","text":{"KOREA":"제가 간이 배밖으로 나오지 않은 이상, 인도자님께 폐를 끼치는 일을 저지를 리가 없잖아요?","JPN":"私がそんなに図々しく、導き手にご迷惑をおかけするはずがないでしょう？","ENG":"Unless I've taken leave of my senses, I'd never do anything to burden you.","TWN":"我又不是膽大包天，怎麼可能做出給你添麻煩的事情呢？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MAID_PRIDE_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"실례했습니다. 제가 착각한 모양이네요.","JPN":"失礼。私が勘違いしたようです。","ENG":"My apologies. I must've been mistaken.","TWN":"失禮了。我好像搞錯了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MAID_PRIDE_NULL_A","text":{"KOREA":"피곤하시니 그럴 수 있죠. 저는 이해한답니다.","JPN":"疲れておられるのです。私は気にしません。","ENG":"It's fine. You're tired, that's all. I understand.","TWN":"你累了，搞錯也可以理解。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAID_PRIDE_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MAID_PRIDE_NULL_A","text":{"KOREA":"클링턴 씨께는 제가 말씀드리고 올 테니, 오늘은 이만 쉬는 게 어떻겠나요?","JPN":"クリントンさんには私が話しておきますので、今日はもうお休みになったらいかがですか？","ENG":"I'll speak to Mr. Clinton for you. Why don't you get some rest?","TWN":"我去跟克林頓先生說，今天就先休息一下吧？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAID_PRIDE_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예. 그러는 편이 좋겠네요.","JPN":"はい。その方が良さそうですね。","ENG":"Yes. That sounds like a good idea.","TWN":"是的，那樣比較好。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"죄송하지만, 먼저 들어가보겠습니다.","JPN":"申し訳ありません、お先に失礼します。","ENG":"Excuse me, I'll retire for the night.","TWN":"不好意思，我先進去。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"}]`);export{e as default};